<?php
namespace App\Http\Controllers\Admin\Content;
use App\Domain\Admin\Content\Progression\CharacterProgressionAdminReadService;use App\Domain\Characters\Progression\CharacterProgressionConfigurationService;use App\Domain\Characters\Progression\Exceptions\CharacterProgressionConfigurationConflict;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\CharacterProgressionRequest;use InvalidArgumentException;
final class CharacterProgressionController extends Controller{public function index(CharacterProgressionAdminReadService $read){return view('admin.content.progression.index',$read->viewModel());}public function update(CharacterProgressionRequest $request,CharacterProgressionConfigurationService $service){try{$service->update($request->user(),$request->validated());return redirect()->route('admin.content.progression.index')->with('status','Configuración de progresión actualizada correctamente.');}catch(CharacterProgressionConfigurationConflict $e){return back()->withInput()->withErrors(['version'=>$e->getMessage()]);}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['progression'=>$e->getMessage()]);}}}
